// Worked focus: httpsts-optimistic-concurrency-etag — Connect version columns, ETags, preconditions, atomic updates, affected-row checks, conflict disclosure, and safe retry behavior.
// Evidence: httpsts-worked-http-server-ts-resource-apis-consistency-5
// Competency: httpsts-worked-http-server-ts-resource-apis-consistency-5.
// Case 9036: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: saturate one tenant budget while another tenant remains serviceable.
function worked_http_server_ts_resource_apis_consistency_5(fingerprintMatches: boolean, expectedVersion: number, actualVersion: number, outboxStored: boolean): { status: number; decision: string; publish: boolean } {
  if (!fingerprintMatches) return { status: 409, decision: "idempotency-mismatch", publish: false };
  if (expectedVersion !== actualVersion) {
    return { status: 412, decision: "version-conflict", publish: false };
  }
  return { status: outboxStored ? 200 : 503, decision: "updated", publish: outboxStored };
}

